mapper.select:
SELECT p.payment_id AS paymentId, p.user_id AS userId, u.email AS email, p.plan_type AS planType, p.amount AS amount, p.status AS status, p.paid_at AS paidAt FROM payments p INNER JOIN users u ON p.user_id = u.user_id WHERE 1 = 1
AND u.email LIKE CONCAT('%', #{email}, '%')
AND p.plan_type = #{planType}
AND p.status = #{status}
ORDER BY p.paid_at DESC
